import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import MainContent from './components/MainContent';
import ATSPanel from './components/ATSPanel';
import { applicationData } from './data/applicationData';
import './App.css';

function App() {
  const [currentStep, setCurrentStep] = useState(0);
  const [steps, setSteps] = useState(['contact', 'websites', 'summary', 'experience', 'education', 'projects', 'skills', 'preview']);
  const [resumeData, setResumeData] = useState({
    contact: {},
    websites: [],
    summary: '',
    experience: [],
    education: [],
    projects: [],
    skills: { technical: [], soft: [], other: [] }
  });

  const goToStep = (stepIndex) => {
    if (stepIndex >= 0 && stepIndex < steps.length) {
      setCurrentStep(stepIndex);
    }
  };

  const reorderSteps = (newSteps) => {
    const currentKey = steps[currentStep];
    setSteps(newSteps);
    const newIndex = newSteps.indexOf(currentKey);
    setCurrentStep(newIndex >= 0 ? newIndex : 0);
  };

  const updateResumeData = (section, data) => {
    setResumeData(prev => ({
      ...prev,
      [section]: data
    }));
  };

  const calculateProgress = () => {
    return ((currentStep + 1) / steps.length) * 100;
  };

  const loadSample = () => {
    const sample = applicationData.sampleResume;
    setResumeData({
      contact: sample.contact || {},
      websites: sample.websites || [],
      summary: sample.summary || '',
      experience: sample.experience || [],
      education: sample.education || [],
      projects: sample.projects || [],
      skills: sample.skills || { technical: [], soft: [], other: [] }
    });
    setCurrentStep(0);
  };

  const normalizeImportedResume = (input) => {
    if (!input || typeof input !== 'object') return null;

    // Direct shape support
    const directShape = {
      contact: input.contact || {
        fullName: input.fullName || input.name || '',
        phone: input.phone || (input.basics && input.basics.phone) || '',
        email: input.email || (input.basics && input.basics.email) || '',
        location: input.location || (input.basics && input.basics.location && (input.basics.location.city || input.basics.location.region)) || '',
        linkedIn: input.linkedIn || (input.basics && input.basics.profiles && (input.basics.profiles.find(p => /linkedin/i.test(p.network)) || {}).url) || ''
      },
      websites: input.websites || (input.basics && input.basics.profiles ? input.basics.profiles.map((p, idx) => ({ id: idx + 1, label: p.network, url: p.url })) : []),
      summary: input.summary || (input.basics && input.basics.summary) || '',
      experience: Array.isArray(input.experience) ? input.experience : (Array.isArray(input.work) ? input.work.map((w, i) => ({
        id: i + 1,
        title: w.position || '',
        company: w.name || '',
        location: (w.location || ''),
        startDate: w.startDate || '',
        endDate: w.endDate || (w.isCurrent ? 'Present' : ''),
        achievements: Array.isArray(w.highlights) ? w.highlights : []
      })) : []),
      education: Array.isArray(input.education) ? input.education : (Array.isArray(input.educationHistory) ? input.educationHistory : (Array.isArray(input.education) ? input.education : [])),
      projects: Array.isArray(input.projects) ? input.projects : [],
      skills: (() => {
        if (input.skills && (Array.isArray(input.skills.technical) || Array.isArray(input.skills.soft) || Array.isArray(input.skills.other))) {
          return input.skills;
        }
        // JSON Resume skills -> flatten to technical
        if (Array.isArray(input.skills)) {
          return {
            technical: input.skills.map(s => s.name || s),
            soft: [],
            other: []
          };
        }
        return { technical: [], soft: [], other: [] };
      })()
    };

    // Ensure ids
    directShape.experience = (directShape.experience || []).map((e, idx) => ({ id: e.id || idx + 1, ...e }));
    directShape.education = (directShape.education || []).map((e, idx) => ({ id: e.id || idx + 1, degree: e.degree || e.studyType || '', school: e.school || e.institution || '', location: e.location || '', graduationDate: e.graduationDate || e.endDate || '' }));
    directShape.projects = (directShape.projects || []).map((p, idx) => ({ id: p.id || idx + 1, name: p.name || '', role: p.role || p.position || '', link: p.link || p.url || '', description: p.description || (Array.isArray(p.highlights) ? p.highlights.join(' ') : '') }));

    return directShape;
  };

  const importResume = (json) => {
    const normalized = normalizeImportedResume(json);
    if (!normalized) return;
    setResumeData(normalized);
    setCurrentStep(0);
    // Optional: adopt steps order if provided
    if (Array.isArray(json.steps)) {
      const valid = json.steps.filter(k => ['contact','websites','summary','experience','education','projects','skills','preview'].includes(k));
      if (valid.length) setSteps(valid);
    }
  };

  return (
    <div className="app">
      <Header />
      <div className="app-layout">
        <Sidebar 
          currentStep={currentStep}
          steps={steps}
          progress={calculateProgress()}
          onStepClick={goToStep}
          onReorderSteps={reorderSteps}
          onLoadSample={loadSample}
          onImportResume={importResume}
        />
        <MainContent 
          steps={steps}
          currentStep={currentStep}
          resumeData={resumeData}
          onUpdateData={updateResumeData}
          onStepChange={goToStep}
        />
        <ATSPanel 
          resumeData={resumeData}
          currentStep={currentStep}
        />
      </div>
    </div>
  );
}

export default App;
